import React, { useEffect, useRef } from 'react';
import { Message } from '../types';

interface MessageListProps {
  messages: Message[];
  isTyping: boolean;
}

const MessageList: React.FC<MessageListProps> = ({ messages, isTyping }) => {
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isTyping]);

  const renderContent = (content: string) => {
    // Basic Markdown Parser (Simplified for speed/weight)
    return content.split('\n').map((line, i) => {
      if (line.startsWith('# ')) return <h1 key={i} className="font-serif text-2xl font-bold mt-4 mb-2">{line.replace('# ', '')}</h1>;
      if (line.startsWith('## ')) return <h2 key={i} className="font-serif text-xl font-bold mt-3 mb-1">{line.replace('## ', '')}</h2>;
      if (line.startsWith('### ')) return <h3 key={i} className="font-serif text-lg font-bold mt-2 mb-1">{line.replace('### ', '')}</h3>;
      if (line.startsWith('* ')) return <li key={i} className="ml-4 list-disc mb-1">{line.replace('* ', '')}</li>;
      if (line.startsWith('---')) return <hr key={i} className="border-[#1C1C1E] my-4" />;

      // Bold text handling
      const boldRegex = /\*\*(.*?)\*\*/g;
      const italicRegex = /\*(.*?)\*/g;
      let parts: (string | JSX.Element)[] = [line];

      // Crude but effective string to JSX converter for bold/italic
      const processParts = (text: string) => {
        let currentParts: (string | JSX.Element)[] = [];
        let lastIndex = 0;
        let match;

        const combinedRegex = /(\*\*.*?\*\*)|(\*.*?\*)/g;
        while ((match = combinedRegex.exec(text)) !== null) {
          if (match.index > lastIndex) {
            currentParts.push(text.substring(lastIndex, match.index));
          }
          const m = match[0];
          if (m.startsWith('**')) {
            currentParts.push(<strong key={match.index} className="font-bold text-white">{m.slice(2, -2)}</strong>);
          } else {
            currentParts.push(<em key={match.index} className="italic">{m.slice(1, -1)}</em>);
          }
          lastIndex = combinedRegex.lastIndex;
        }
        if (lastIndex < text.length) {
          currentParts.push(text.substring(lastIndex));
        }
        return currentParts.length > 0 ? currentParts : [text];
      };

      return <p key={i} className="mb-2 leading-relaxed text-[#F5F5F7]/90">{processParts(line)}</p>;
    });
  };

  return (
    <div ref={scrollRef} className="flex-1 overflow-y-auto px-4 pt-24 pb-32 space-y-6">
      {messages.map((msg) => (
        <div 
          key={msg.id} 
          className={`flex w-full ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
        >
          <div 
            className={`max-w-[85%] px-4 py-3 rounded-xl transition-all ${
              msg.role === 'user' 
                ? 'bg-[#1C1C1E] text-[#F5F5F7] rounded-br-none' 
                : 'bg-transparent border-l-2 border-[#8E8E93] rounded-none'
            }`}
          >
            {msg.role === 'assistant' && (
              <div className="font-serif italic text-xs text-[#8E8E93] mb-2">Roundtables Assistant</div>
            )}
            <div className="text-sm">
              {renderContent(msg.content)}
            </div>
            {msg.sources && msg.sources.length > 0 && (
              <div className="mt-4 pt-3 border-t border-[#1C1C1E]">
                <div className="text-[10px] text-[#8E8E93] uppercase tracking-wider mb-2">Intelligence Sources</div>
                <div className="flex flex-wrap gap-2">
                  {msg.sources.map((source, idx) => (
                    <a 
                      key={idx} 
                      href={source.uri} 
                      target="_blank" 
                      rel="noopener noreferrer"
                      className="text-[10px] bg-[#1C1C1E] hover:bg-[#2C2C2E] px-2 py-1 rounded text-[#8E8E93] border border-[#2C2C2E] transition-colors"
                    >
                      {source.title.length > 25 ? source.title.substring(0, 25) + '...' : source.title}
                    </a>
                  ))}
                </div>
              </div>
            )}
          </div>
        </div>
      ))}
      {isTyping && (
        <div className="flex justify-start">
          <div className="bg-transparent border-l-2 border-[#8E8E93] px-4 py-3">
            <div className="flex space-x-1">
              <div className="w-1.5 h-1.5 bg-[#8E8E93] rounded-full animate-bounce"></div>
              <div className="w-1.5 h-1.5 bg-[#8E8E93] rounded-full animate-bounce [animation-delay:0.2s]"></div>
              <div className="w-1.5 h-1.5 bg-[#8E8E93] rounded-full animate-bounce [animation-delay:0.4s]"></div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default MessageList;

import React, { useState, useRef, useEffect } from 'react';

interface ChatInputProps {
  onSendMessage: (message: string) => void;
  disabled: boolean;
}

const ChatInput: React.FC<ChatInputProps> = ({ onSendMessage, disabled }) => {
  const [input, setInput] = useState('');
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  const handleSubmit = (e?: React.FormEvent) => {
    e?.preventDefault();
    if (input.trim() && !disabled) {
      onSendMessage(input.trim());
      setInput('');
      if (textareaRef.current) {
        textareaRef.current.style.height = 'auto';
      }
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSubmit();
    }
  };

  useEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto';
      textareaRef.current.style.height = `${Math.min(textareaRef.current.scrollHeight, 120)}px`;
    }
  }, [input]);

  return (
    <div className="fixed bottom-0 left-0 right-0 p-4 bg-gradient-to-t from-[#0A0A0A] via-[#0A0A0A] to-transparent">
      <form 
        onSubmit={handleSubmit}
        className="max-w-screen-md mx-auto flex items-end gap-2 bg-[#1C1C1E] rounded-2xl p-2 border border-[#2C2C2E]"
      >
        <textarea
          ref={textareaRef}
          rows={1}
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={handleKeyDown}
          placeholder="Ask about themes, trends, or logistics..."
          disabled={disabled}
          className="flex-1 bg-transparent border-none focus:ring-0 text-sm py-2 px-3 resize-none max-h-[120px] text-[#F5F5F7] placeholder-[#8E8E93]"
        />
        <button
          type="submit"
          disabled={!input.trim() || disabled}
          className="p-2 rounded-xl bg-white text-black disabled:opacity-30 disabled:cursor-not-allowed transition-all"
        >
          <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" className="w-5 h-5">
            <path d="M3.478 2.405a.75.75 0 00-.926.94l2.432 7.905H13.5a.75.75 0 010 1.5H4.984l-2.432 7.905a.75.75 0 00.926.94 60.519 60.519 0 0018.445-8.986.75.75 0 000-1.218A60.517 60.517 0 003.478 2.405z" />
          </svg>
        </button>
      </form>
    </div>
  );
};

export default ChatInput;

import React, { useState, useCallback, useEffect } from 'react';
import Header from './components/Header';
import MessageList from './components/MessageList';
import ChatInput from './components/ChatInput';
import { Message } from './types';
import { INITIAL_GREETING } from './constants';
import { generateAssistantResponse } from './services/geminiService';

const App: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    {
      id: 'initial',
      role: 'assistant',
      content: INITIAL_GREETING,
      timestamp: new Date()
    }
  ]);
  const [isTyping, setIsTyping] = useState(false);

  const handleSendMessage = useCallback(async (text: string) => {
    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: text,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMessage]);
    setIsTyping(true);

    try {
      // Prepare history for Gemini API
      const history = messages
        .filter(m => m.id !== 'initial') // Skip intro formatting for model history context unless needed
        .map(m => ({
          role: m.role === 'user' ? 'user' : 'model' as 'user' | 'model',
          parts: [{ text: m.content }]
        }));

      const response = await generateAssistantResponse(text, history);

      const assistantMessage: Message = {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        content: response.text,
        timestamp: new Date(),
        sources: response.sources
      };

      setMessages(prev => [...prev, assistantMessage]);
    } catch (error) {
      const errorMessage: Message = {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        content: "I encountered a strategic friction while processing that request. Please try again or rephrase.",
        timestamp: new Date()
      };
      setMessages(prev => [...prev, errorMessage]);
    } finally {
      setIsTyping(false);
    }
  }, [messages]);

  return (
    <div className="flex flex-col h-full max-w-screen-md mx-auto relative bg-[#0A0A0A]">
      <Header />
      <MessageList messages={messages} isTyping={isTyping} />
      <ChatInput onSendMessage={handleSendMessage} disabled={isTyping} />

      {/* Decorative Blur Elements */}
      <div className="fixed top-0 left-0 w-full h-32 bg-gradient-to-b from-[#0A0A0A] to-transparent pointer-events-none z-40"></div>
    </div>
  );
};

export default App;

