      {isTyping && (
        <div className="flex justify-start">
          <div className="border-l border-[#8E8E93]/30 pl-6 py-4">
            <div className="flex space-x-2">
              <div className="w-1.5 h-1.5 bg-[#8E8E93] rounded-full animate-pulse"></div>
