import { GoogleGenAI } from "@google/genai";
import { SYSTEM_PROMPT } from "../constants";

// Fix: Strictly use process.env.API_KEY directly for initialization as per guidelines
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const streamAssistantResponse = async function* (
  message: string,
  history: { role: 'user' | 'model'; parts: { text: string }[] }[]
) {
  try {
    const result = await ai.models.generateContentStream({
      model: 'gemini-3-flash-preview',
      contents: [
        ...history,
        { role: 'user', parts: [{ text: message }] }
      ],
      config: {
        systemInstruction: SYSTEM_PROMPT,
        tools: [{ googleSearch: {} }],
        temperature: 0.7,
      },
    });

    for await (const chunk of result.stream) {
      const text = chunk.text;
      if (text) {
        yield { type: 'text', content: text };
      }
    }

    // Retrieve the final response object to extract grounding metadata (sources)
    const response = await result.response;
    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
      title: chunk.web?.title || 'Source',
      uri: chunk.web?.uri || '',
    })).filter((s: any) => s.uri) || [];

    if (sources.length > 0) {
      yield { type: 'sources', content: sources };
    }

  } catch (error) {
    console.error("Gemini Error:", error);
    throw error;
  }
};

import React, { useState, useCallback, useEffect } from 'react';
import Header from './components/Header';
import MessageList from './components/MessageList';
import ChatInput from './components/ChatInput';
import Onboarding from './components/Onboarding';
import { Message } from './types';
import { INITIAL_GREETING } from './constants';
import { streamAssistantResponse } from './services/geminiService';

const App: React.FC = () => {
  const [showOnboarding, setShowOnboarding] = useState(true);
  const [messages, setMessages] = useState<Message[]>([
    {
      id: 'initial',
      role: 'assistant',
      content: INITIAL_GREETING,
      timestamp: new Date()
    }
  ]);
  const [isTyping, setIsTyping] = useState(false);

  // Check if user has already seen onboarding in this session
  useEffect(() => {
    const skip = sessionStorage.getItem('skipOnboarding');
    if (skip) setShowOnboarding(false);
  }, []);

  const handleEnter = () => {
    setShowOnboarding(false);
    sessionStorage.setItem('skipOnboarding', 'true');
  };

  const handleFeedback = (messageId: string, type: 'up' | 'down') => {
    setMessages(prev => prev.map(msg => 
      msg.id === messageId 
        ? { ...msg, feedback: msg.feedback === type ? undefined : type }
        : msg
    ));
  };

  const handleSendMessage = useCallback(async (text: string) => {
    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: text,
      timestamp: new Date()
    };

    // Add user message immediately
    setMessages(prev => [...prev, userMessage]);
    setIsTyping(true);

    // Create a placeholder for the assistant response
    const assistantMsgId = (Date.now() + 1).toString();
    const assistantMessage: Message = {
      id: assistantMsgId,
      role: 'assistant',
      content: '', // Start empty for streaming
      timestamp: new Date()
    };

    setMessages(prev => [...prev, assistantMessage]);

    try {
      const history = messages
        .filter(m => m.id !== 'initial')
        .map(m => ({
          role: m.role === 'user' ? 'user' : 'model' as 'user' | 'model',
          parts: [{ text: m.content }]
        }));

      const stream = streamAssistantResponse(text, history);

      for await (const update of stream) {
        if (update.type === 'text') {
          setMessages(prev => prev.map(msg => 
            msg.id === assistantMsgId 
              ? { ...msg, content: msg.content + update.content }
              : msg
          ));
        } else if (update.type === 'sources') {
          setMessages(prev => prev.map(msg => 
            msg.id === assistantMsgId 
              ? { ...msg, sources: update.content }
              : msg
          ));
        }
      }

    } catch (error) {
      // If an error occurs, update the message to show the error
      setMessages(prev => prev.map(msg => 
        msg.id === assistantMsgId
          ? { ...msg, content: "I encountered a strategic friction while processing that request. Please try again or rephrase." }
          : msg
      ));
    } finally {
      setIsTyping(false);
    }
  }, [messages]);

  return (
    <>
      {showOnboarding && <Onboarding onEnter={handleEnter} />}
      <div className="flex flex-col h-full max-w-screen-md mx-auto relative bg-[#0A0A0A]">
        <Header />
        <MessageList 
          messages={messages} 
          isTyping={isTyping} 
          onFeedback={handleFeedback}
        />
        <ChatInput onSendMessage={handleSendMessage} disabled={isTyping} />

        {/* Decorative Blur Elements */}
        <div className="fixed top-0 left-0 w-full h-32 bg-gradient-to-b from-[#0A0A0A] to-transparent pointer-events-none z-40"></div>
      </div>
    </>
  );
};

export default App;

